import React from 'react';
import { useI18n } from '../../i18n/I18nContext';

// Translation keys for sub-practice options
const SUB_PRACTICE_OPTIONS = {
  vocabulary: [
    { id: 'random-word', labelKey: 'subPractice.vocabulary.randomWord', defaultLabel: 'Random Word' },
    { id: 'random-image', labelKey: 'subPractice.vocabulary.randomImage', defaultLabel: 'Random Image' },
    { id: 'match-image-word', labelKey: 'subPractice.vocabulary.matchImageWord', defaultLabel: 'Match Image-Word' },
    { id: 'listening', labelKey: 'subPractice.vocabulary.listening', defaultLabel: 'Listening' },
    { id: 'type-opposite', labelKey: 'subPractice.vocabulary.typeOpposite', defaultLabel: 'Type Opposite' },
    { id: 'match-opposites', labelKey: 'subPractice.vocabulary.matchOpposites', defaultLabel: 'Match Opposites' },
    { id: 'build-word', labelKey: 'subPractice.vocabulary.buildWord', defaultLabel: 'Build Word' },
  ],
  grammar: [
    { id: 'gender-articles', labelKey: 'subPractice.grammar.genderArticles', defaultLabel: 'Gender & Articles' },
    { id: 'verbs-conjugation', labelKey: 'subPractice.grammar.verbsConjugation', defaultLabel: 'Verb Conjugation' },
    { id: 'possessives', labelKey: 'subPractice.grammar.possessives', defaultLabel: 'Possessives' },
    { id: 'word-order', labelKey: 'subPractice.grammar.wordOrder', defaultLabel: 'Word Order' },
  ],
  reading: [
    { id: 'story', labelKey: 'subPractice.reading.story', defaultLabel: 'Story' },
    { id: 'interesting-fact', labelKey: 'subPractice.reading.interestingFact', defaultLabel: 'Interesting Fact' },
  ],
  speaking: [
    { id: 'question-practice', labelKey: 'subPractice.speaking.question', defaultLabel: 'Question Practice' },
    { id: 'monologue', labelKey: 'subPractice.speaking.monologue', defaultLabel: 'Monologue' },
  ],
  writing: [
    { id: 'writing-question', labelKey: 'subPractice.writing.question', defaultLabel: 'Writing Question' },
    { id: 'storytelling', labelKey: 'subPractice.writing.storytelling', defaultLabel: 'Storytelling' },
  ],
};

const SubPracticeMenu = ({ mainCategory, activeSubPractice, onSubPracticeSelect }) => {
  const { t } = useI18n();

  if (!mainCategory || !SUB_PRACTICE_OPTIONS[mainCategory]) {
    return null; // No main category selected or no sub-options for it
  }

  const optionsForMainCategory = SUB_PRACTICE_OPTIONS[mainCategory];

  const getSubPracticeLabel = (subPracticeId) => {
    const subPracticeDefinition = optionsForMainCategory.find(sp => sp.id === subPracticeId);
    if (subPracticeDefinition) {
      return t(subPracticeDefinition.labelKey, subPracticeDefinition.defaultLabel);
    }
    return subPracticeId; // Fallback
  };
  
  // Title for the sub-practice section, using main category's translated name
  // The mainCategory prop is the ID like 'vocabulary', 'grammar'
  // We need a general translation for the main category names if not already available via a specific key.
  // Example: t('mainCategory.vocabulary', 'Vocabulary')
  const mainCategoryTitle = t(`mainCategory.${mainCategory.toLowerCase()}`, mainCategory.charAt(0).toUpperCase() + mainCategory.slice(1));


  if (activeSubPractice) {
    // A sub-practice is active, show only that one as a button.
    // Clicking it signals to the parent to toggle/go back.
    return (
      <div style={{ margin: '20px 0', padding: '10px', border: '1px solid #eee', borderRadius: '5px' }}>
        <h3 style={{ marginTop: '0', textAlign: 'center' }}>
          {mainCategoryTitle} - {t('subPractice.selectedLabel', 'Selected Exercise:')}
        </h3>
        <div style={{ display: 'flex', justifyContent: 'center', flexWrap: 'wrap', gap: '10px' }}>
          <button
            key={activeSubPractice}
            onClick={() => onSubPracticeSelect(activeSubPractice)}
            style={{
              padding: '8px 12px',
              fontSize: '0.9rem',
              cursor: 'pointer',
              backgroundColor: '#28a745', // Active style
              color: 'white',
              border: '1px solid #1e7e34',
              borderRadius: '4px',
              minWidth: '150px',
              textAlign: 'center',
            }}
            aria-pressed="true"
          >
            {getSubPracticeLabel(activeSubPractice)}
          </button>
        </div>
      </div>
    );
  } else {
    // No sub-practice is active, show all options for the current mainCategory.
    const subPracticesToDisplay = optionsForMainCategory.map(option => ({
      id: option.id,
      label: getSubPracticeLabel(option.id)
    }));

    return (
      <div style={{ margin: '20px 0', padding: '10px', border: '1px solid #eee', borderRadius: '5px' }}>
        <h3 style={{ marginTop: '0', textAlign: 'center' }}>
          {mainCategoryTitle} - {t('subPractice.selectLabel', 'Select Exercise:')}
        </h3>
        <div style={{ display: 'flex', justifyContent: 'center', flexWrap: 'wrap', gap: '10px' }}>
          {subPracticesToDisplay.map((option) => (
            <button
              key={option.id}
              onClick={() => onSubPracticeSelect(option.id)}
              style={{
                padding: '8px 12px',
                fontSize: '0.9rem',
                cursor: 'pointer',
                backgroundColor: '#f8f9fa', // Default style
                color: 'black',
                border: '1px solid #ccc',
                borderRadius: '4px',
                minWidth: '150px',
                textAlign: 'center',
              }}
              aria-pressed="false"
            >
              {option.label}
            </button>
          ))}
        </div>
      </div>
    );
  }
};

export default SubPracticeMenu;
